'use client';
import { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { useAuth } from '@/context/AuthContext';
import { useToast } from '@/hooks/use-toast';
import SearchInput from '@/components/ui/SearchInput';
import { Card } from '@/components/ui/Card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Loading } from '@/components/ui/Loading';
import NotFound from '@/components/ui/NotFound';
import { EventCategory } from '@/types';


export default function HostRegisteredUsersPage() {
  const { token } = useAuth();
  const { toast } = useToast();
  const [events, setEvents] = useState<EventCategory[]>([]);
  const [loading, setLoading] = useState(false);
  const [search, setSearch] = useState('');

  useEffect(() => {
    const fetchData = async () => {
      if (!token) return;
      setLoading(true);
      try {
        const res = await fetch(`http://localhost:8080/host/events`, {
          headers: {
            ...(token ? { Authorization: `Bearer ${token}` } : {}),
            'Content-Type': 'application/json',
          },
        });
        const data = await res.json();
        console.log("data",data)
        // Assume backend can include registeredUsers; if not, leave empty arrays
        const mapped: EventCategory[] = (data.events || []).map((e: any) => ({
          _id: e._id,
          title: e.title,
          registeredUsers: e.registeredUsers || [],
        }));
        setEvents(data.event  );
      } catch (err: any) {
        toast({ title: 'Error', description: err?.message || 'Failed to load', className: 'bg-red-600 text-white border-0' });
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [token]);

  const filtered = events;
  if (loading) return <Loading />;

  return (
    <div className='max-w-6xl mx-auto p-6 space-y-6'>
      <div className='flex items-center justify-between gap-4 flex-wrap'>
        <motion.h1 initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} className='text-2xl font-bold text-purple-900'>
          Registered Users
        </motion.h1>
        <SearchInput name='Users' searchQuery={search} setSearchQuery={setSearch} setCurrentPage={() => {}} />
      </div>

      {filtered?.length === 0 ? (
        <NotFound message='No events found' />
      ) : (
        <div className='space-y-6'>
          {filtered?.map((ev) => (
            <motion.div key={ev._id} initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}>
              <Card className='p-4'>
                <div className='flex items-center justify-between mb-4'>
                  <h2 className='text-lg font-semibold text-purple-800'>{ev.title}</h2>
                  <span className='text-sm text-gray-500'>Total: {ev.registeredUsers?.length || 0}</span>
                </div>
                {(ev.registeredUsers || []).length === 0 ? (
                  <NotFound message='No registeredUsers for this event' />
                ) : (
                  <div className='overflow-x-auto'>
                    <Table>
                      <TableHeader className='bg-gray-50'>
                        <TableRow>
                          <TableHead>Name</TableHead>
                          <TableHead>Email</TableHead>
                          <TableHead>Status</TableHead>
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        {/* {ev.registeredUsers!.map((r) => (
                          <motion.tr key={r} initial={{ opacity: 0 }} animate={{ opacity: 1 }} className='hover:bg-purple-50/50'>
                            <TableCell className='font-medium'>{r.name}</TableCell>
                            <TableCell>{r.email}</TableCell>
                            <TableCell className='capitalize'>{r.status}</TableCell>
                          </motion.tr>
                        ))} */}
                      </TableBody>
                    </Table>
                  </div>
                )}
              </Card>
            </motion.div>
          ))}
        </div>
      )}
    </div>
  );
}


